// 1. Get OpenAI response string
let rawText = $json.output[0].content[0].text;

// 2. Remove markdown formatting (```json ... ```) and whitespace
const cleanJson = rawText.replace(/```json|```/g, "").trim();

// 3. Parse and return
try {
  const parsedData = JSON.parse(cleanJson);
  return parsedData;
} catch (error) {
  return {
    error: "JSON parsing failed",
    raw: rawText,
    cleaned: cleanJson
  };
}

// 1. Get original article HTML body from note.com
let bodyHtml = $node["Get Article from Note.com API"].json.data.body;

// 2. Get the array of old/new URL pairs from Aggregate node
const urlPairs = $json.url_map;

// 3. Replace all note.com image URLs with WordPress URLs
for (const pair of urlPairs) {
  if (pair.old_url && pair.new_url) {
    // Replace assets.st-note.com URLs with nurse-katekyo.jp URLs
    // Using split/join to replace ALL occurrences
    bodyHtml = bodyHtml.split(pair.old_url).join(pair.new_url);
  }
}

// 4. Return the updated body HTML
return {
  final_body: bodyHtml
};
